const settings = $('Load Global Settings').first()?.json ?? {};
const request = $('Preview Refund Request Email Webhook').first()?.json ?? $input.first()?.json ?? {};
const query = request.query ?? request;
const headers = request.headers ?? {};
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const truthy = (value) => ['1', 'true', 'yes', 'y', 'on'].includes(clean(value).toLowerCase());
const deriveBaseUrl = (headers, fallback) => {
  const forwardedProto = clean(headers['x-forwarded-proto']);
  const forwardedHost = clean(headers['x-forwarded-host']);
  const host = forwardedHost || clean(headers.host);
  const forwardedPort = clean(headers['x-forwarded-port']);
  if (!host) return fallback;
  const proto = forwardedProto || 'http';
  let authority = host;
  if (forwardedPort && !authority.includes(':')) {
    const isDefaultPort = (proto === 'http' && forwardedPort === '80') || (proto === 'https' && forwardedPort === '443');
    if (!isDefaultPort) authority = `${authority}:${forwardedPort}`;
  }
  return `${proto}://${authority}`;
};
const fallbackBaseUrl = clean(settings.n8n_base_url) || 'http://n8n:5678';
const n8nBaseUrl = deriveBaseUrl(headers, fallbackBaseUrl);
const refundId = Number.parseInt(clean(query.refund_id), 10);
const actionTypeRaw = clean(query.action_type);
const actionType = actionTypeRaw || (clean(query.template_key) === 'request_bank_details' ? 'request_bank_details' : 'submit_refund_request');
const templateKey = clean(query.template_key) || (actionType === 'request_bank_details' ? 'request_bank_details' : 'refund_request_treasury');
const defaultDeliveryMode = clean(settings.default_delivery_mode).toLowerCase() === 'production' ? 'production' : 'test';
const forceTest = truthy(query.test_mode) || clean(query.delivery_mode).toLowerCase() === 'test' || defaultDeliveryMode !== 'production';
const deliveryMode = forceTest ? 'test' : 'production';
const returnUrl = clean(query.return_url) || `${n8nBaseUrl}/webhook/refunds${Number.isInteger(refundId) ? `?id=${refundId}` : ''}`;
const validActions = ['request_bank_details', 'submit_refund_request'];
const errorMessage = !Number.isInteger(refundId)
  ? 'Refund id is required.'
  : !validActions.includes(actionType)
    ? 'Refund email action is not recognised.'
    : !templateKey
      ? 'Email template is required.'
      : '';
return [{ json: {
  refund_id: refundId,
  action_type: actionType,
  template_key: templateKey,
  signature_template_key: settings.email_signature_template_key || 'signature',
  sender_name: settings.email_sender_name || 'Steve Short',
  reply_to: settings.email_reply_to || 'members.avondaleltc@gmail.com',
  delivery_mode: deliveryMode,
  test_recipient: clean(settings.default_test_recipient) || 'steve.short@gmail.com',
  return_url: returnUrl,
  n8n_base_url: n8nBaseUrl,
  error_message: errorMessage
} }];

const input = $('Resolve Preview Request').first().json ?? {};
const sqlLiteral = (value) => {
  if (value === null || value === undefined || value === '') return 'NULL';
  return "'" + String(value).replace(/'/g, "''") + "'";
};
const sql = `with main_template as (
  select template_key, template_name, subject_template, text_template, html_template
  from public.email_templates
  where template_key = ${sqlLiteral(input.template_key)}
    and is_active = true
    and template_type = 0
  order by id desc
  limit 1
), signature_template as (
  select template_key, template_name, subject_template, text_template, html_template
  from public.email_templates
  where template_key = ${sqlLiteral(input.signature_template_key || 'signature')}
    and is_active = true
    and template_type = 2
  order by id desc
  limit 1
)
select
  (select template_key from main_template) as template_key,
  (select template_name from main_template) as template_name,
  (select subject_template from main_template) as subject_template,
  (select text_template from main_template) as text_template,
  (select html_template from main_template) as html_template,
  (select template_key from signature_template) as signature_template_key,
  (select text_template from signature_template) as signature_text_template,
  (select html_template from signature_template) as signature_html_template,
  case
    when not exists (select 1 from main_template) then 'Email template ' || ${sqlLiteral(input.template_key)} || ' was not found or is not an active message template'
    else null
  end as error_message;`;
return [{ json: { ...input, sql } }];

const input = $('Resolve Preview Request').first()?.json ?? {};
const context = $('Load Preview Context').first()?.json ?? {};
const refund = $('Load Refund Data').first()?.json ?? {};
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const actionMeta = {
  request_bank_details: {
    label: 'Request Bank Details',
    preview_title: 'Preview Bank Details Request',
    intro: 'Review and edit the member-facing email before sending it.',
    send_label: 'Send Bank Details Request',
    allowed_statuses: ['New Request', 'Request Bank Details']
  },
  submit_refund_request: {
    label: 'Submit Refund Request',
    preview_title: 'Preview Treasury Refund Request',
    intro: 'Review and edit the treasury request before sending it.',
    send_label: 'Send Treasury Request',
    allowed_statuses: ['Bank Details Obtained', 'Submitted for Refund']
  }
};
const meta = actionMeta[input.action_type] ?? null;
const intendedRecipient = input.action_type === 'submit_refund_request' ? 'treasury.avondaleltc@gmail.com' : clean(refund.member_email);
const errorMessage = input.error_message || context.error_message || !refund.id
  ? (input.error_message || context.error_message || 'Refund not found.')
  : !meta
    ? 'Refund email action is not recognised.'
    : !meta.allowed_statuses.includes(clean(refund.status))
      ? `${meta.label} is only available when the refund status is ${meta.allowed_statuses.join(' or ')}.`
      : !intendedRecipient
        ? `No email address was found for ${clean(refund.refund_for) || 'this refund'}.`
        : '';
return [{ json: {
  ...input,
  ...refund,
  template_name: context.template_name || input.template_key,
  subject_template: context.subject_template || '',
  text_template: context.text_template || '',
  html_template: context.html_template || '',
  signature_text_template: context.signature_text_template || '',
  signature_html_template: context.signature_html_template || '',
  intended_recipient: intendedRecipient,
  preview_title: meta?.preview_title || 'Preview Refund Email',
  preview_intro: meta?.intro || 'Review and edit the rendered email.',
  send_label: meta?.send_label || 'Send Email',
  action_label: meta?.label || input.action_type,
  error_message: errorMessage
} }];

const primary = $('Merge Preview Data').first()?.json ?? {};
const fallback = $('Resolve Preview Request').first()?.json ?? {};
const message = primary.error_message || fallback.error_message || 'Unable to prepare the refund email preview.';
const returnUrl = primary.return_url || fallback.return_url || '#';
const redirectTo = `${returnUrl}${String(returnUrl).includes('?') ? '&' : '?'}error=${encodeURIComponent(message)}${primary.refund_id ? `&id=${encodeURIComponent(primary.refund_id)}` : ''}`;
const escapeHtml = (value) => String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/\"/g, '&quot;').replace(/'/g, '&#39;');
const html = `<!doctype html><html lang="en"><head><meta charset="utf-8"><meta http-equiv="refresh" content="0; url=${escapeHtml(redirectTo)}"><meta name="viewport" content="width=device-width, initial-scale=1"><title>Refund Email Preview Failed</title><style>body{margin:0;padding:24px;background:#f7f8fc;font-family:Lato,'Helvetica Neue',Arial,sans-serif;color:#2e3d4e}.panel{max-width:760px;margin:0 auto;background:#fff;border:1px solid #e2e8f0;border-radius:18px;box-shadow:0 18px 40px rgba(53,72,91,.08);padding:28px}.button{display:inline-flex;align-items:center;justify-content:center;padding:12px 18px;border-radius:999px;text-decoration:none;font-weight:700;background:linear-gradient(135deg,#509ee3 0%,#2f80d8 100%);color:#fff}</style></head><body><div class="panel"><h1>Refund Email Preview Failed</h1><p>${escapeHtml(message)}</p><p><a class="button" href="${escapeHtml(redirectTo)}">Back to refunds</a></p></div></body></html>`;
return [{ json: { html } }];

const input = $('Merge Preview Data').first().json ?? {};
const parseIsoDate = (value) => {
  const raw = String(value ?? '').trim();
  const match = raw.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (!match) return null;
  const [, yearText, monthText, dayText] = match;
  return { year: Number.parseInt(yearText, 10), month: Number.parseInt(monthText, 10), day: Number.parseInt(dayText, 10) };
};
const formatDate = (value) => {
  const parsed = parseIsoDate(value);
  if (!parsed) return String(value ?? '').trim();
  return `${String(parsed.day).padStart(2, '0')}/${String(parsed.month).padStart(2, '0')}/${parsed.year}`;
};
const formatMoney = (value) => {
  const rounded = Math.round((Number(value) + Number.EPSILON) * 100) / 100;
  const text = Number.isInteger(rounded) ? String(rounded) : rounded.toFixed(2).replace(/\.00$/, '').replace(/(\.\d)0$/, '$1');
  return `£${text}`;
};
const nameToken = input.action_type === 'request_bank_details' ? (input.refund_for ?? '') : (input.name ?? '');
const tokenMap = {
  '{{name}}': nameToken,
  '{{requested_by}}': input.name ?? '',
  '{{refund_for}}': input.refund_for ?? '',
  '{{reason}}': input.reason ?? '',
  '{{membership}}': input.membership ?? '',
  '{{amount}}': formatMoney(input.amount),
  '{{from_date}}': formatDate(input.from_date),
  '{{to_date}}': formatDate(input.to_date),
  '{{months}}': String(input.months ?? ''),
  '{{refund}}': formatMoney(input.refund),
  '{{status}}': input.status ?? '',
  '{{explanation}}': input.explanation ?? '',
  '{{$json.name}}': nameToken,
  '{{$json.requested_by}}': input.name ?? '',
  '{{$json.refund_for}}': input.refund_for ?? '',
  '{{$json.reason}}': input.reason ?? '',
  '{{$json.membership}}': input.membership ?? '',
  '{{$json.amount}}': formatMoney(input.amount),
  '{{$json.from_date}}': formatDate(input.from_date),
  '{{$json.to_date}}': formatDate(input.to_date),
  '{{$json.months}}': String(input.months ?? ''),
  '{{$json.refund}}': formatMoney(input.refund),
  '{{$json.status}}': input.status ?? '',
  '{{$json.explanation}}': input.explanation ?? ''
};
const applyTokens = (value) => {
  let rendered = String(value ?? '');
  for (const [token, replacement] of Object.entries(tokenMap)) {
    rendered = rendered.split(token).join(String(replacement));
  }
  return rendered.trim();
};
const emailType = input.html_template && !input.text_template ? 'html' : 'text';
const bodySource = emailType === 'html' ? (input.html_template ?? input.text_template ?? '') : (input.text_template ?? input.html_template ?? '');
const signatureSource = emailType === 'html' ? (input.signature_html_template ?? input.signature_text_template ?? '') : (input.signature_text_template ?? input.signature_html_template ?? '');
const joinSeparator = emailType === 'html' ? '<br><br>' : '\n\n';
const actualRecipient = input.delivery_mode === 'production' ? input.intended_recipient : input.test_recipient;
return [{ json: {
  refund_id: input.refund_id,
  action_type: input.action_type,
  action_label: input.action_label,
  preview_title: input.preview_title,
  preview_intro: input.preview_intro,
  send_label: input.send_label,
  refund_for: input.refund_for,
  membership: input.membership,
  template_key: input.template_key,
  template_name: input.template_name,
  delivery_mode: input.delivery_mode,
  test_recipient: input.test_recipient,
  intended_recipient: input.intended_recipient,
  actual_recipient: actualRecipient,
  return_url: input.return_url,
  sender_name: input.sender_name,
  reply_to: input.reply_to,
  rendered_subject: applyTokens(input.subject_template ?? 'Refund email'),
  rendered_message: [applyTokens(bodySource), applyTokens(signatureSource)].filter(Boolean).join(joinSeparator).trim(),
  email_type: emailType,
  send_url: `${input.n8n_base_url}/webhook/send-refund-request-email`
} }];

const item = $('Render Preview Data').first().json ?? {};
const escapeHtml = (value) => String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/\"/g, '&quot;').replace(/'/g, '&#39;');
const bodyPreview = escapeHtml(item.rendered_message).replace(/\r?\n/g, '&#10;');
const subjectPreview = escapeHtml(item.rendered_subject);
const modeChecked = item.delivery_mode !== 'production' ? ' checked' : '';
const modeLabel = item.delivery_mode === 'production' ? 'Production' : 'Test';
const recipientSummary = item.delivery_mode === 'production' ? escapeHtml(item.actual_recipient) : `${escapeHtml(item.actual_recipient)} (intended recipient: ${escapeHtml(item.intended_recipient)})`;
const html = `<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>${escapeHtml(item.preview_title)}</title><style>:root{color-scheme:light;--bg:#f7f8fc;--panel:#ffffff;--ink:#2e3d4e;--muted:#6b7785;--line:#e2e8f0;--accent:#509ee3;--accent-dark:#2f80d8;--soft:#f2f7fd;--button-soft:#eef2f7}*{box-sizing:border-box}body{margin:0;padding:24px;background:linear-gradient(180deg,#fbfcfe 0%,var(--bg) 100%);font-family:Lato,'Helvetica Neue',Arial,sans-serif;color:var(--ink)}.wrap{max-width:960px;margin:0 auto;display:grid;gap:20px}.panel{background:var(--panel);border:1px solid var(--line);border-radius:18px;box-shadow:0 18px 40px rgba(53,72,91,.08);padding:28px}h1{margin:0 0 10px;font-size:32px;line-height:1.05;letter-spacing:-.02em}.meta{margin:0;color:var(--muted);line-height:1.5}.summary{display:grid;gap:14px;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));margin-top:20px}.summary-card{border:1px solid var(--line);border-radius:14px;padding:16px;background:var(--soft)}.summary-card h2{margin:0 0 8px;font-size:13px;text-transform:uppercase;letter-spacing:.08em;color:var(--muted)}.summary-card p{margin:0;font-size:17px;line-height:1.4}.email-form{display:grid;gap:16px;margin-top:18px}.email-form label{display:grid;gap:8px;font-weight:700}.email-form input[type=text],.email-form textarea{width:100%;border:1px solid var(--line);border-radius:12px;padding:12px 14px;font:inherit;background:#fff;color:var(--ink)}.email-form textarea{min-height:320px;resize:vertical;line-height:1.5}.checkbox-wrap{display:inline-flex;align-items:center;gap:10px;font-weight:600}.checkbox-wrap input{width:18px;height:18px}.actions{display:flex;gap:12px;flex-wrap:wrap;align-items:center}.button,.secondary{display:inline-flex;align-items:center;justify-content:center;padding:12px 18px;border-radius:999px;text-decoration:none;font-weight:700;border:0;cursor:pointer;font:inherit}.button{background:linear-gradient(135deg,var(--accent) 0%,var(--accent-dark) 100%);color:#fff;box-shadow:0 10px 24px rgba(80,158,227,.22)}.secondary{background:var(--button-soft);color:var(--ink);border:1px solid var(--line)}</style></head><body><div class="wrap"><section class="panel"><h1>${escapeHtml(item.preview_title)}</h1><p class="meta">${escapeHtml(item.preview_intro)}</p><div class="summary"><div class="summary-card"><h2>Refund For</h2><p>${escapeHtml(item.refund_for)}</p></div><div class="summary-card"><h2>Membership</h2><p>${escapeHtml(item.membership)}</p></div><div class="summary-card"><h2>Template</h2><p>${escapeHtml(item.template_name)}</p></div><div class="summary-card"><h2>Recipient</h2><p>${recipientSummary}</p></div><div class="summary-card"><h2>Mode</h2><p>${escapeHtml(modeLabel)}</p></div></div><form class="email-form" method="POST" action="${escapeHtml(item.send_url)}"><input type="hidden" name="refund_id" value="${escapeHtml(item.refund_id)}"><input type="hidden" name="action_type" value="${escapeHtml(item.action_type)}"><input type="hidden" name="template_key" value="${escapeHtml(item.template_key)}"><input type="hidden" name="return_url" value="${escapeHtml(item.return_url)}"><input type="hidden" name="email_type" value="${escapeHtml(item.email_type)}"><input type="hidden" name="intended_recipient" value="${escapeHtml(item.intended_recipient)}"><input type="hidden" name="refund_for" value="${escapeHtml(item.refund_for)}"><input type="hidden" name="membership" value="${escapeHtml(item.membership)}"><label><span>Subject</span><input type="text" name="rendered_subject" value="${subjectPreview}" required></label><label><span>Message</span><textarea name="rendered_message" required>${bodyPreview}</textarea></label><label><span>Mode</span><span class="checkbox-wrap"><input type="checkbox" name="test_mode" value="1"${modeChecked}> Send in test mode</span></label><div class="actions"><button type="submit" class="button">${escapeHtml(item.send_label)}</button><a class="secondary" href="${escapeHtml(item.return_url)}">Back to Refunds</a></div></form></section></div></body></html>`;
return [{ json: { html } }];
